import Card from "./card/Cards";

function PostList() {
  const products = [
    { id: 1, price: 1200, title: "Айран 0.25", image: "https://via.placeholder.com/150" },
    { id: 2, price: 950, title: "Молоко 1л", image: "https://via.placeholder.com/150" },
    { id: 3, price: 800, title: "Кефир 0.5", image: "https://via.placeholder.com/150" },
    { id: 4, price: 600, title: "Сметана 0.2", image: "https://via.placeholder.com/150" },
    { id: 5, price: 1400, title: "Йогурт клубничный", image: "https://via.placeholder.com/150" },
    { id: 6, price: 1100, title: "Творог 200г", image: "https://via.placeholder.com/150" }
  ];

  return (
    <div className="cards-container">
      {products.map((item) => (
        <Card
          key={item.id}
          price={item.price}
          title={item.title}
          image={item.image}
        />
      ))}
    </div>
  );
}

export default PostList;
